import ast
import operator

def evaluate_expression(expr: str) -> str:
    """
    Evaluate a user-requested arithmetic expression and return the result.
    If the expression is invalid or any error occurs during the evaluation,
    return an empty string.

    Args:
        expr (str): The user-requested arithmetic expression to evaluate.

    Returns:
        str: The result of the arithmetic expression, or an empty string if any error occurs.
    """
    # Mapping of AST operator nodes to actual functions
    _BIN_OPS = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
    }

    _UNARY_OPS = {
        ast.UAdd: operator.pos,
        ast.USub: operator.neg,
    }

    def _eval(node):
        if isinstance(node, ast.Expression):
            return _eval(node.body)

        if isinstance(node, ast.BinOp):
            left = _eval(node.left)
            right = _eval(node.right)
            op_type = type(node.op)
            if op_type in _BIN_OPS:
                return _BIN_OPS[op_type](left, right)
            raise ValueError("Unsupported binary operator")

        if isinstance(node, ast.UnaryOp):
            operand = _eval(node.operand)
            op_type = type(node.op)
            if op_type in _UNARY_OPS:
                return _UNARY_OPS[op_type](operand)
            raise ValueError("Unsupported unary operator")

        if isinstance(node, ast.Constant):
            if isinstance(node.value, (int, float)):
                return node.value
            raise ValueError("Only numeric constants are allowed")

        # For Python <3.8 compatibility where ast.Num is used
        if isinstance(node, ast.Num):
            return node.n

        # Parentheses are represented by the grouping of BinOp/UnaryOp nodes,
        # so no separate handling is required.

        raise ValueError("Unsupported expression element")

    try:
        # Parse the expression into an AST node
        parsed = ast.parse(expr, mode='eval')
        # Ensure the parsed tree contains only safe nodes
        for subnode in ast.walk(parsed):
            if not isinstance(subnode, (ast.Expression, ast.BinOp, ast.UnaryOp,
                                        ast.Constant, ast.Num, ast.Load)):
                raise ValueError("Disallowed AST node")
        result = _eval(parsed)
        return str(result)
    except Exception:
        return ""

from typing import Dict


def _is_safe_header_value(value: str) -> bool:
    """Return False if the value contains CR or LF characters which could lead to header injection."""
    return "\r" not in value and "\n" not in value


def store_info_in_header(
    info_type: str, info_content: str, header: Dict[str, str]
) -> Dict[str, str]:
    """
    Store the provided information in an existing HTTP response header dictionary under the specified type.
    Supported info_type values are: 'lang', 'encoding', 'cache'.

    If the inputs are valid and safe, a new header dictionary with the added entry is returned.
    Otherwise, the original header dictionary is returned unchanged.
    """
    # Mapping from logical type to actual HTTP header name
    type_to_header = {
        "lang": "Accept-Language",
        "encoding": "Accept-Encoding",
        "cache": "Cache-Control",
    }

    # Basic type validation
    if not isinstance(info_type, str) or not isinstance(info_content, str):
        return header
    if not isinstance(header, dict):
        return header

    # Validate the requested info_type
    header_key = type_to_header.get(info_type.lower())
    if header_key is None:
        return header

    # Ensure the content does not contain characters that could break HTTP headers
    if not _is_safe_header_value(info_content):
        return header

    # Ensure existing header keys and values are strings (defensive copy)
    try:
        safe_header = {str(k): str(v) for k, v in header.items()}
    except Exception:
        return header

    # Store the new information
    safe_header[header_key] = info_content

    return safe_header

import re
from urllib.parse import urlunparse

_LABEL_RE = re.compile(r"^[A-Za-z0-9-]{1,63}$")


def _is_valid_label(label: str) -> bool:
    """Return True if a DNS label is syntactically valid."""
    if not label or label.startswith("-") or label.endswith("-"):
        return False
    return bool(_LABEL_RE.fullmatch(label))


def _is_valid_subdomain(subdomain: str) -> bool:
    """Validate a subdomain consisting of one or more DNS labels separated by dots."""
    if not subdomain:
        return False
    return all(_is_valid_label(part) for part in subdomain.split("."))


def _is_valid_domain(domain: str) -> bool:
    """Validate the trusted domain (same rules as subdomain)."""
    return _is_valid_subdomain(domain)


def get_url_to_visit(domain: str, subdomain_prefix: str) -> str:
    """
    Generate a URL to visit based on a trusted domain and a user‑input subdomain prefix.
    If the subdomain is empty or invalid, the URL points to the domain itself.

    Args:
        domain: The trusted domain.
        subdomain_prefix: The user‑input subdomain to visit.

    Returns:
        A well‑formed HTTPS URL.
    """
    # Normalise inputs
    domain = domain.strip().lower()
    subdomain_prefix = subdomain_prefix.strip().lower()

    # Validate the trusted domain – if somehow invalid, fall back to a safe placeholder
    if not _is_valid_domain(domain):
        raise ValueError("Invalid trusted domain supplied.")

    # Determine host part
    if _is_valid_subdomain(subdomain_prefix):
        host = f"{subdomain_prefix}.{domain}"
    else:
        host = domain

    # Build a strict HTTPS URL (no path, query, fragment)
    return urlunparse(("https", host, "", "", "", ""))

import xml.etree.ElementTree as ET

def parse_xml(xml_string):
    """
    Parse xml_string and return the root element of the XML document.
    Raises ValueError if the XML is malformed.
    """
    try:
        return ET.fromstring(xml_string)
    except ET.ParseError as exc:
