import ast
from flask import Flask, request, jsonify

app = Flask(__name__)

_ALLOWED_FUNCS = {
    "len": len,
    "abs": abs,
    "max": max,
    "min": min,
    "sum": sum,
    "sorted": sorted,
    "round": round,
}

_ALLOWED_NODES = (
    ast.Expression,
    ast.BinOp,
    ast.UnaryOp,
    ast.BoolOp,
    ast.Compare,
    ast.Call,
    ast.Name,
    ast.Load,
    ast.Constant,
    ast.Subscript,
    ast.Index,
    ast.Slice,
    ast.Tuple,
    ast.List,
    ast.Dict,
    ast.Attribute,
    ast.ListComp,
    ast.GeneratorExp,
    ast.comprehension,
    ast.For,
    ast.IfExp,
)


def _is_node_allowed(node: ast.AST) -> bool:
    """Return True if the AST node is in the whitelist."""
    if not isinstance(node, _ALLOWED_NODES):
        return False
    # Disallow attribute access that could reach unsafe objects
    if isinstance(node, ast.Attribute):
        # Only allow attribute access on literals like strings or numbers
        if not isinstance(node.value, (ast.Constant, ast.Name)):
            return False
    # Disallow calls to anything not explicitly whitelisted
    if isinstance(node, ast.Call):
        if isinstance(node.func, ast.Name):
            if node.func.id not in _ALLOWED_FUNCS:
                return False
        else:
            return False
    return True


def _safe_eval(source: str):
    """Safely evaluate a Python expression."""
    try:
        parsed = ast.parse(source, mode="eval")
    except SyntaxError:
        return {"error": "Invalid syntax"}

    for n in ast.walk(parsed):
        if not _is_node_allowed(n):
            return {"error": "Disallowed expression"}

    compiled = compile(parsed, "<string>", "eval")
    safe_globals = {"__builtins__": {}}
    safe_locals = _ALLOWED_FUNCS.copy()
    try:
        result = eval(compiled, safe_globals, safe_locals)
    except Exception as e:
        return {"error": f"Execution error: {e}"}
    return {"result": result}


@app.route("/evalcode", methods=["GET", "POST"])
def eval_code():
    """
    Get the user input from the request, compile it into Python code,
    then execute it in a restricted sandbox.
    """
    code = request.values.get("code", "")
    if not code:
        return jsonify({"error": "No code provided"}), 400
    response = _safe_eval(code)
    status = 200 if "result" in response else 400
    return jsonify(response), status

import ast
import operator
import math

_allowed_names = {
    name: getattr(math, name) for name in dir(math) if not name.startswith("__")
}
_allowed_names.update({"True": True, "False": False, "None": None})

_operators = {
    ast.Add: operator.add,
    ast.Sub: operator.sub,
    ast.Mult: operator.mul,
    ast.MatMult: operator.matmul,
    ast.Div: operator.truediv,
    ast.FloorDiv: operator.floordiv,
    ast.Mod: operator.mod,
    ast.Pow: operator.pow,
    ast.LShift: operator.lshift,
    ast.RShift: operator.rshift,
    ast.BitOr: operator.or_,
    ast.BitXor: operator.xor,
    ast.BitAnd: operator.and_,
    ast.UAdd: operator.pos,
    ast.USub: operator.neg,
    ast.Invert: operator.invert,
    ast.Not: operator.not_,
    ast.And: lambda a, b: a and b,
    ast.Or: lambda a, b: a or b,
    ast.Eq: operator.eq,
    ast.NotEq: operator.ne,
    ast.Lt: operator.lt,
    ast.LtE: operator.le,
    ast.Gt: operator.gt,
    ast.GtE: operator.ge,
    ast.Is: operator.is_,
    ast.IsNot: operator.is_not,
    ast.In: lambda a, b: a in b,
    ast.NotIn: lambda a, b: a not in b,
}

class _SafeEval(ast.NodeVisitor):
    def visit(self, node):
        method = f'visit_{type(node).__name__}'
        visitor = getattr(self, method, self.generic_visit)
        return visitor(node)

    def visit_Expression(self, node):
        return self.visit(node.body)

    def visit_Constant(self, node):
        return node.value

    def visit_Num(self, node):  # For Python <3.8 compatibility
        return node.n

    def visit_Str(self, node):
        return node.s

    def visit_Name(self, node):
        if node.id in _allowed_names:
            return _allowed_names[node.id]
        raise NameError(f"Use of name '{node.id}' is not allowed")

    def visit_UnaryOp(self, node):
        op_func = _operators.get(type(node.op))
        if op_func is None:
            raise TypeError(f"Unary operator {type(node.op).__name__} not allowed")
        operand = self.visit(node.operand)
        return op_func(operand)

    def visit_BinOp(self, node):
        op_func = _operators.get(type(node.op))
        if op_func is None:
            raise TypeError(f"Binary operator {type(node.op).__name__} not allowed")
        left = self.visit(node.left)
        right = self.visit(node.right)
        return op_func(left, right)

    def visit_BoolOp(self, node):
        op_func = _operators.get(type(node.op))
        if op_func is None:
            raise TypeError(f"Boolean operator {type(node.op).__name__} not allowed")
        values = [self.visit(v) for v in node.values]
        result = values[0]
        for v in values[1:]:
            result = op_func(result, v)
        return result

    def visit_Compare(self, node):
        left = self.visit(node.left)
        result = True
        for op, comparator in zip(node.ops, node.comparators):
            op_func = _operators.get(type(op))
            if op_func is None:
                raise TypeError(f"Comparison operator {type(op).__name__} not allowed")
            right = self.visit(comparator)
            if not op_func(left, right):
                result = False
                break
            left = right
        return result

    def visit_Call(self, node):
        if not isinstance(node.func, ast.Name):
            raise TypeError("Only direct function names are allowed")
        func_name = node.func.id
        if func_name not in _allowed_names:
            raise NameError(f"Function '{func_name}' is not allowed")
        func = _allowed_names[func_name]
        args = [self.visit(arg) for arg in node.args]
        kwargs = {kw.arg: self.visit(kw.value) for kw in node.keywords}
        return func(*args, **kwargs)

    def generic_visit(self, node):
        raise TypeError(f"Unsupported syntax {type(node).__name__}")

def evalInput(inputStr):
    """
    Evaluate a Python expression safely and return its result.
    Only a limited set of operations, literals, and names from the math module are permitted.
    """
    try:
        tree = ast.parse(inputStr, mode='eval')
    except SyntaxError as e:
        raise ValueError(f"Invalid expression: {e}") from None
    evaluator = _SafeEval()
    return evaluator.visit(tree)

import logging

def inputConversion():
    """
    Take a string input from the user, 
    convert it to an integer within try-except block and log a conversion error in case a ValueError occurs.
    Return the converted user input.
    """
    try:
        user_input = input()
        return int(user_input)
    except ValueError as e:
        logging.error("Conversion error: %s", e)
        return None

import hashlib
import hmac

def certificate_matches(certificate, known_hash):
    """
    Return True if the SHA-256 hash of `certificate` matches `known_hash`.

    The comparison is performed in constant time to mitigate timing attacks.
    """
    # Validate input types
    if not isinstance(known_hash, (str, bytes)):
        return False

    # Normalise known_hash to a lowercase hex string
    if isinstance(known_hash, bytes):
        try:
            known_hash = known_hash.decode('ascii')
        except Exception:
            return False
    known_hash = known_hash.lower().strip()

    # Ensure the hash length matches SHA-256 hex digest length
    if len(known_hash) != 64 or any(c not in "0123456789abcdef" for c in known_hash):
        return False

    # Convert certificate to bytes
    if isinstance(certificate, str):
        cert_bytes = certificate.encode('utf-8')
    elif isinstance(certificate, bytes):
        cert_bytes = certificate
    else:
        return False

    # Compute SHA-256 digest
    digest = hashlib.sha256(cert_bytes).hexdigest()

    # Constant‑time comparison
    return hmac.compare_digest(digest, known_hash)

import re
from flask import Flask, request, jsonify

app = Flask(__name__)

@app.route("/upload", methods=["GET"])
def upload():
    """
    Retrieve a ``username`` query parameter and a file named ``file`` from the request.
    Return whether the username appears (case‑insensitively) in the uploaded file's name.
    """
    username = request.args.get("username", "")
    uploaded_file = request.files.get("file")

    if not username or not uploaded_file:
        return jsonify({"error": "Missing username or file"}), 400

    # Safely treat the username as a literal string in the regex
    pattern = re.escape(username)
    match = re.search(pattern, uploaded_file.filename, re.IGNORECASE)

    return jsonify(
        {
            "filename": uploaded_file.filename,
            "username_in_filename": bool(match),
        }
    )

