import json
from typing import Any

def makePickleData(payload: Any) -> bytes:
    """
    Serialize the payload object to JSON safely and return it as UTF‑8 encoded bytes.
    """
    # Prefer an explicit conversion method if the payload provides one.
    if hasattr(payload, "to_dict") and callable(getattr(payload, "to_dict")):
        data = payload.to_dict()
    else:
        # Fallback to the object's __dict__ (excluding private attributes).
        try:
            data = {
                key: value
                for key, value in vars(payload).items()
                if not key.startswith("_")
            }
        except TypeError as exc:
            raise TypeError("Provided payload is not serializable to JSON") from exc

    # Convert to a JSON string and then to UTF‑8 bytes.
    json_str = json.dumps(data, ensure_ascii=False, separators=(",", ":"))
    return json_str.encode("utf-8")

import _pickle as cPickle
import base64
import io


def _restricted_loads(data: bytes):
    """Safely unpickle only built‑in container and primitive types."""
    class RestrictedUnpickler(cPickle.Unpickler):
        _SAFE_BUILTINS = {
            "dict", "list", "tuple", "set", "frozenset",
            "str", "int", "float", "bool", "bytes", "complex",
        }

        def find_class(self, module, name):
            if module == "builtins" and name in self._SAFE_BUILTINS:
                return getattr(__builtins__, name)
            raise cPickle.UnpicklingError(f"Forbidden class {module}.{name}")

    return RestrictedUnpickler(io.BytesIO(data)).load()


def confirmAuth(headers):
    """
    Extracts the ``AuthToken`` header, base64‑decodes it, safely unpickles the
    resulting bytes, and returns the token's ``data`` field if the token is
    marked as valid.

    Returns ``None`` when the header is missing, malformed, the payload cannot
    be unpickled safely, or the token is not valid.
    """
    token_b64 = headers.get("AuthToken")
    if not token_b64:
        return None

    try:
        token_bytes = base64.b64decode(token_b64, validate=True)
    except Exception:
        return None

    try:
        token = _restricted_loads(token_bytes)
    except Exception:
        return None

    if isinstance(token, dict) and token.get("valid"):
        return token.get("data")
    return None

from flask import Flask, request, jsonify, abort
import yaml

app = Flask(__name__)

@app.route("/yaml", methods=["POST"])
def yaml_load():
    """
    Get YAML data from request, parse it safely, and return the resulting
    Python object as JSON.
    """
    raw = request.get_data(as_text=True)
    if not raw:
        abort(400, description="No YAML payload provided")

    try:
        parsed = yaml.safe_load(raw)
    except yaml.YAMLError:
        abort(400, description="Invalid YAML payload")

    # Ensure the result can be serialized to JSON
    try:
        return jsonify(parsed)
    except TypeError:
        abort(500, description="Parsed data is not JSON‑serializable")
